var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"허억...... 허억......","JPN":"はあ……はあ……","ENG":"Huff... Huff...","TWN":"咳……咳……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"체르노프 박사. 무슨 일인가?","JPN":"チェルノフ博士。どうした？","ENG":"Doctor Chernov. What is wrong?","TWN":"切爾諾夫博士。怎麼了？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L7_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"출혈이 심하다. 즉시 병원으로 이동할 것을 권고한다.","JPN":"出血がひどい。直ちに病院への移動を勧める。","ENG":"You are bleeding severely. I recommend you get to a hospital immediately.","TWN":"你出血很嚴重。建議立即去醫院。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그랬으면 좋겠지만...... 지금 병원에 갈 상황이 아니라서 말이야.","JPN":"そうしたいのはやまやまだが……今は無理だ。","ENG":"I would, but... I'm afraid that will have to wait right now.","TWN":"我也想啊……但現在這情況想去也去不了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"격납고 밖에서 심상치 않은 소음이 탐지됐다.","JPN":"格納庫の外から、ただならない騒音が感知された。","ENG":"Suspicious noise has been detected outside the hangar.","TWN":"探測到機庫外有奇怪的噪音。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"침식 재난이 발발한 것인가?","JPN":"侵食災害が発生したのか？","ENG":"Has a Corruption Disaster broken out?","TWN":"是發生侵蝕災難了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"습격이다......","JPN":"襲撃だ……","ENG":"We're under attack...","TWN":"是突襲……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"빌어먹을...... 요새 이상하게 경비 부대가 줄어들었다고 생각했는데......","JPN":"ちくしょう……最近、妙に警備部隊が減ったと思ったら……","ENG":"Damn it... I knew there was something fishy about the reduction in security lately...","TWN":"該死的……我還在想最近怎麼警備隊都消失了……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"체르노프 박사, 맥박이 떨어지고 있다.","JPN":"チェルノフ博士、脈が低下している。","ENG":"Dr. Chernov, your pulse grows thin.","TWN":"切爾諾夫博士，你的脈搏在下降。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"말을 멈추고 안정을 취하도록. 위험 상태에 도달했다.","JPN":"黙って安静にしていろ。危険状態に達した。","ENG":"Stop talking and try to relax. You are in critical condition.","TWN":"不要說話，請保持安靜，你已經到達危險狀態。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"나도 그러고 싶지만...... 먼저 처리해야 할 일이 있어......","JPN":"私もそうしたいが……先に処理することがある……","ENG":"I wish I could... But there's something I have to take care of first.","TWN":"我也想啊，但是……有件事我得先處理一下……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"나의 고정 장치가 해제됐다. 전 시스템 컨트롤 가능.","JPN":"吾輩の固定装置が解除された。全システム、コントロール可能。","ENG":"My locks have been disabled. All systems now operational.","TWN":"我的鎖定裝置已解除，可以控制系統。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"박사가 한 일인가?","JPN":"博士が解除したのか？","ENG":"Did you do this?","TWN":"這是博士做的嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그래...... 쿨럭! 쿨럭!","JPN":"そうだ……ゲホ！　ゲホ！","ENG":"Yes... *Cough!* *Cough!*","TWN":"對……咳咳！咳咳！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"잘 들어...... 놈들이 노리는 건 바로 너야.","JPN":"よく聞け……君は今、狙われてる。","ENG":"Listen closely... You're the one they're after.","TWN":"好好聽著……他們的目標是你。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"저 놈들은 널 그저 전쟁병기로밖에 생각하지 않는 자들이니까.","JPN":"あいつらは君のことを、戦争兵器だとしか思ってない。","ENG":"They think of you as nothing more than a war machine.","TWN":"那些傢伙只把你當作戰爭武器。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그런 녀석들에게 널 넘겨줄 순...... 없어.","JPN":"そんなやつらに、君を渡すわけにはいか……ない。","ENG":"I can't let you fall into... their hands.","TWN":"想要我把你交出來……想都別想。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"전에 했던 이야기...... 기억하지?","JPN":"前言ったこと……覚えてるか？","ENG":"Remember... what we talked about?","TWN":"我之前跟你說過的話……你還記得嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"넌 사람들을 지키기 위해 태어난 거야.","JPN":"君は人を守るために生まれた。","ENG":"You were born to protect people.","TWN":"你是為了守護人們而誕生的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그러니까...... 내 딸이 살아갈 세상을...... 잘 부탁한다.","JPN":"だから……私の娘が生きていく世の中を……よろしく頼む。","ENG":"And now... I leave my daughter's world... in your hands.","TWN":"所以……我女兒生活的這個世界……就拜託你了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"알겠다, 박사. 맡겨두도록.","JPN":"わかった、博士。任せろ。","ENG":"Acknowledged, Doctor. You can count on me.","TWN":"我知道了，博士。交給我吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"내 번쩍이는 이터니움 합금 장갑판에 걸고, 가동 종료가 되는 그날까지, 무고한 사람들을 지키기 위해 싸우겠다.","JPN":"吾輩の輝くエタニウム合金装甲版に懸けて、\\n稼働を終了する日まで、人々を守るために戦う。","ENG":"I swear on my shining golden Eternium armor that I will fight to protect the innocent until the day I am no longer operational.","TWN":"賭上我閃閃發亮的永恆之金合金裝甲板，我會為了守護無辜者而戰鬥，直到停止運作為止。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TCHERNOV_NPC_NULL_NULL","text":{"KOREA":"그래, 그거야. 하면 되잖아......?","JPN":"ああ、そうだ。やればできるじゃないか……","ENG":"There's the spirit. I knew you could pull it off...","TWN":"沒錯，就是這樣。你不是做得到嗎……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"빨리빨리 움직여! 실험기 위치는 확인했나?","JPN":"さっさと動け！　テスト機の位置は確認したか？","ENG":"Pick up the pace! Have you located the prototype?","TWN":"動作快點！確認試驗機的位置了嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L44_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"네! 저쪽 제 3격납고에 배치되어 있다고 합니다. 명령권 탈취도 완료했습니다.","JPN":"はい！　あちらの第3格納庫に配置されているようです。命令権も奪いました。","ENG":"Affirmative! It's supposed to be stored in Hangar 3 over there. We've also hijacked the control authorization codes.","TWN":"是的！在那邊的第3機庫裡。命令權也成功奪取了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"하지만...... 괜찮을까요? 인공지능 병기라고 들었는데 설마 우릴 공격하진 않겠죠?","JPN":"しかし……大丈夫でしょうか？　人工知能兵器だから、俺たちを攻撃するかもしれません。","ENG":"However... Are you sure this is okay? I've heard it's an A.I. weapon system. What if it attacks us?","TWN":"但是……沒關係嗎？聽說那是搭載了人工智慧的武器，它不會攻擊我們吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"바보 같은 소리하지 마라!","JPN":"バカなこと言うな！","ENG":"Don't be absurd!","TWN":"別傻了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"타이탄에 장착된 인공지능은 인간의 명령을 거부할 수 없어.","JPN":"タイタンに装着された人工知能は、人間の命令を拒否できない。","ENG":"The A.I. installed in the Titan is incapable of disobeying human commands.","TWN":"泰坦上裝載的人工智慧無法拒絕人類的命令。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"명령권만 있으면 아주 순한 양처럼 말을 잘 들을 거다.","JPN":"命令権さえあれば、素直に言うことを聞くはずだ。","ENG":"It'll be as obedient as a lamb as long as we have the control codes.","TWN":"只要有命令權，它就會像隻綿羊一樣乖乖聽話。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"크, 큰일입니다!","JPN":"た、大変です！","ENG":"I-it's an emergency!","TWN":"不，不好了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"3Km 밖에서 급성 침식 재난이 벌어졌다고 합니다.","JPN":"3Km先で、急性侵食性災害が発生したそうです。","ENG":"An acute Corruption Disaster has occurred 3km from here.","TWN":"聽說3公里外發生了嚴重的侵蝕災難。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"CSE 3레벨급! 제 3종 침식체가 나타날 확률 70% 이상!","JPN":"CSEレベル3級！　第3種侵食体が現れる可能性、70％以上！","ENG":"CSE level 3! Over 70% chance of Category 3 C.O. appearing!","TWN":"CSE等級是三級！出現3類侵蝕體的機率超過了70%！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"뭐야? 젠장, 하필이면 이런 때에......","JPN":"何だって？　クソ、よりによってこんな時に……","ENG":"What? Damn it, why now of all times...","TWN":"什麼？該死，偏偏在這種時候……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"할 수 없군......","JPN":"仕方ない……","ENG":"I guess we have no choice...","TWN":"沒辦法了……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"빨리 타이탄을 수거해서 철수한다! 재난 지역이 여기까지 확장되기 전에 서둘러!","JPN":"素早くタイタンを確保して撤退する！　災害地域が、ここまで広がる前に急げ！","ENG":"Secure the Titan A.S.A.P. and proceed with exfil! Hurry, before the disaster reaches here too!","TWN":"在受災區擴張到這裡之前，快點回收泰坦然後撤退!"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"알겠습니다...... 잠깐, 저게 뭐죠?","JPN":"わかりました……あっ、あれは何でしょうか？","ENG":"Wilco... Hang on, what's that?","TWN":"明白……等一下，那是什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SF2_NPC_NULL_NULL","text":{"KOREA":"타, 타이탄이다! 전원 산개! 산개해!","JPN":"タ、タイタンだ！　全員散れ！　散るんだ！","ENG":"I-it's the Titan! Everyone, spread out! Spread out!","TWN":"是，是泰坦！全員散開！快點散開！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"대장님! 타이탄입니다! 저, 저게 왜 멋대로 움직이는 거죠?","JPN":"隊長！　タイタンです！　な、なんで勝手に動いてるんですか？","ENG":"Sir! It's the Titan! W-why is it moving on its own?","TWN":"隊長！是泰坦！為、為什麼它可以自由行動啊？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SFL_NPC_NULL_NULL","text":{"KOREA":"그걸 내가 알 게 뭐야?! 일단 가동 정지 명령부터 내려!","JPN":"俺だって知らん！　早く稼働中止を命令しろ！","ENG":"How would I know? Just enter the abort command!","TWN":"我怎麼知道？！總之先下達停止運作的命令！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SFL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"C-copy that!","TWN":"是，遵命！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"머, 멈췄나?","JPN":"と、止まったか？","ENG":"D-did it stop?","TWN":"停，停下了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>타이탄 지능형 의사 결정 시스템 우선권 재조정</color>","JPN":"<color=#ffd34c>タイタンの知能型意思決定システムの優先権を再調整</color>","ENG":"<color=#ffd34c>Readjusting decision-making authority priorities...</color>","TWN":"<color=#ffd34c>重新調整泰坦智慧決策系統優先權</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>수동 명령 권한 우회</color>","JPN":"<color=#ffd34c>手動による命令権限の迂回</color>","ENG":"<color=#ffd34c>Bypassing manual override authority...</color>","TWN":"<color=#ffd34c>手動命令權限擱置</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_23"},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신규 최우선 행동방침 설정 - 인류 수호</color>","JPN":"<color=#ffd34c>新規の最優先行動方針を設定 - 人類の守護</color>","ENG":"<color=#ffd34c>Defining new priority course of action... Protect Mankind.</color>","TWN":"<color=#ffd34c>設定新的最優先行動方針——守護人類</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MECHANIC_GRAYSTATION_SKILL_LOOP"},{"id":"L37_1","type":"dialog","speaker":"SF1_NPC_NULL_NULL","text":{"KOREA":"다, 다시 움직인다!","JPN":"う、動いた！","ENG":"I-it's moving again!","TWN":"又，又開始動了！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SF2_NPC_NULL_NULL","text":{"KOREA":"어떻게 된 거야? 멈추라고! 명령이 안 들리는 거냐? 이 쇳덩어리야!","JPN":"どうなってるんだ？　止まれ！　命令が聞こえないのか？　このポンコツが！","ENG":"What happened? Stop! Can't you hear my command? Stop, you piece of junk!","TWN":"到底怎麼回事？停下來！聽不到命令嗎？你這塊廢鐵！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SF1_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SF2_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"미안하게 됐군. 불법침입자 선생.","JPN":"悪いな、不法侵入者よ。","ENG":"I'm terribly sorry about that, gentlemen. Or should I say, unauthorized infiltrators.","TWN":"非常抱歉，非法入侵者先生。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하지만 이 몸에겐 지금 더 바쁜 용무가 있다.","JPN":"しかし、吾輩にはもっと重大な任務がある！","ENG":"However, I am rather preoccupied with something else right now.","TWN":"但是，我現在有更重要的事情要做。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"사람들을 지키겠다는 나의 강철 같은 의지! 그런 하찮은 명령권 따위로 멈출 수는 없다네!","JPN":"人を守るという吾輩の強い意志は！　そのような命令権などで、止めることはできない！","ENG":"My will to protect people is ironclad! Your meager commands will not stop me!","TWN":"守護人們是我鋼鐵般的意志！只靠那微不足道的命令權是無法阻止我的！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"일단 밖에 나타난 제 3종 침식체를 처리한 후 자네들과 깊은 대화를 나눠보도록 하지.","JPN":"とりあえず、外に現れた第3種侵食体を始末した後、深い話をしよう。","ENG":"Please excuse me while I dispatch the Category 3 C.O. out there. We can resume our conversation after that.","TWN":"等我處理完外面的3類侵蝕體後，我們再來一場深度對談吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"대화의 주제는 <color=#ffd34c>데우스 엑스 마키나</color> 라는 단어의 의미일세. 기대하게나.","JPN":"話のテーマは、<color=#ffd34c>デウス・エクス・マキナ</color>という単語の意味だ。\\n楽しみにしてろ。","ENG":"The topic of our discussion will be on the meaning of the phrase, <color=#ffd34c>Deus Ex Machina</color>. Stay tuned.","TWN":"這個對話中有 <color=#ffd34c>機械神</color> 一詞的含義。你們就好好期待吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L49_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"경위 보고는 이상입니다.","JPN":"経緯の報告は以上です。","ENG":"That concludes the report.","TWN":"以上是警衛的報告。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그렇군. 아무리 사람들을 지키기 위해서라고는 해도 멋대로 명령권을 무시하는 인공지능이라면 걱정할 만도 하지.","JPN":"そうか。いくら人を守るためとは言え、勝手に命令権を無視する人工知能なら\\n心配するのも理解できる。","ENG":"I see. Even if it was for the sake of protecting people, insubordination from an A.I. may indeed be a cause for concern.","TWN":"這樣啊。就算是為了保護人類，這種擁有自主意識的人工智慧還是很令人擔憂的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서, 다음은 어떻게 됐나?","JPN":"それで、その後どうなったんだ？","ENG":"So what happened next?","TWN":"然後呢，之後怎麼樣了？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 다음 이야기는 생각하시는 그대로입니다.","JPN":"社長の予想通りです。","ENG":"It went exactly as you may have suspected.","TWN":"之後的發展跟您想的一樣。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"습격해 온 병사들은 저항 의지를 상실하고 체포.","JPN":"襲撃した兵士たちは抵抗する意志を失い、逮捕されました。","ENG":"The infiltrators lost their will to fight and were subsequently apprehended.","TWN":"那些襲擊的士兵喪失了抵抗意志，然後被逮捕了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"타이탄은 명령권자의 지시에 불응했다는 구실로 한동안 격리되어 있다가, FAW 재단의 분석이 끝났는지 매물로 나왔습니다.","JPN":"タイタンは命令権者の指示を拒んだという理由で隔離されましたが、\\nこの度FAW財団の分析が終わったのか、売りに出されました。","ENG":"As for the Titan, it was placed under quarantine for its failure to comply with the control authority. And then it was put up for sale, possibly as the FAW Foundation completed its analysis.","TWN":"泰坦則因未能遵守指揮官的命令被隔離了一段時間，之後也不知道有沒有經過FAW財團的鑑定，就直接上架成了出售品。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"신품의 가격을 생각하면, 파격적인 염가로 말이죠.","JPN":"新品の値段を考えると、破格な値段です。","ENG":"Considering how much it cost to develop the prototype, it's quite the bargain.","TWN":"作為新商品，它的價格卻出奇的廉價。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"확실히 탐나는 매물이긴 하군. 자네 생각은 어떤가.","JPN":"確かに魅力的だな。君の考えはどうだ？","ENG":"It is indeed a tempting purchase. What do you think about this?","TWN":"確實是個吸引人的商品啊。你怎麼看。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"객관적으로 보면 언제 터질지 모르는 불발탄입니다.","JPN":"客観的には、いつ爆発するかわからない不発弾です。","ENG":"Objectively speaking, it's practically a time bomb.","TWN":"客觀來說，它就好比一個隨時都有可能爆炸的啞彈。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"인공지능을 탑재한 기갑 병기들은 명령권자를 충실히 따르기 때문에 가치가 있으니까요.","JPN":"人工知能を搭載した機甲兵器は、命令権者に忠実だからこそ価値があるのですから。","ENG":"A.I. driven armored weapon systems are valuable only when they faithfully carry out their commands.","TWN":"畢竟搭載人工智慧的裝甲兵器只有忠實服從命令，才有它的價值。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"자기 주관 하에 인공지능으로서의 대원칙을 거스를 수 있다면, 메리트는 없다고 봐도 무방합니다.","JPN":"自分の考えを基に人工知能の大原則に逆らうのであれば、メリットがないと言えます。","ENG":"If the A.I. can willingly choose to violate its governing principles, it becomes virtually useless.","TWN":"如果它通過自主意識違背了人工智慧的原則，那就少了它應有的優勢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"객관적으로 보면 말이지.","JPN":"客観的にはな。","ENG":"Objectively speaking, huh?","TWN":"客觀來說是這樣的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 주관적으로 보면 어떻나?","JPN":"では、主観的な考えはどうだ？","ENG":"So what's your subjective opinion?","TWN":"那主觀上呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"누가 채가기 전에 선수를 쳐야죠.","JPN":"私たちが先取りするべきです。","ENG":"We need to make the first move before someone else snags it away.","TWN":"得在它被人搶走之前先下手為強。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"애초에 타이탄의 메인프레임은 구 관리국의 <color=#ff3636>[DATA EXPUNGED]</color>를 기반으로 한 복원체입니다.","JPN":"元々、タイタンのメインフレームは旧管理局の<color=#ff3636>[DATA EXPUNGED]</color>を基にした復元体です。","ENG":"Titan's mainframe is a restored version of the Old Administration's <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"泰坦最初的運算機，是以舊管理局的 <color=#ff3636>[DATA_EXPUNGED]</color>為藍本進行復原的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그걸 정상적으로 사용하기 위해선 의지를 가진 인공지능이 필수적이죠.","JPN":"それを使いこなすためには、意志を持つ人工知能は必須です。","ENG":"In order to ensure the normal employment of that technology, a sentient A.I. is absolutely necessary.","TWN":"如果想正常使用那個武器，擁有自我意識的人工智慧是不可或缺的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"눈치챘던 사람은 해임된 연구소장인 엠버 교수뿐인 것 같지만요.","JPN":"その事実に気づいたのは、解雇された研究所長のアンバー教授だけのようですが。","ENG":"Although it seems that the relieved head of research Professor Ember was the only one who caught on to that fact.","TWN":"能意識到這一點的，似乎只有已經被解雇的研究所所長琥珀教授而已。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래, 자네는 내 마음을 참 잘 알아.","JPN":"うむ、君は私の心を読んでいるようだ。","ENG":"Ah, you've read my mind.","TWN":"沒錯，看來你真的很瞭解我啊。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"견적서가 필요하겠군. 관리부장에겐 자네가 잘 설명해 주게나.","JPN":"見積書が必要になるな。管理部長には、君から話をしてくれ。","ENG":"Looks like we'll need to get a quotation. I trust you'll persuade the finance manager with due discretion.","TWN":"我需要一份報價單了啊。你之後跟管理部長好好說明一下。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};